import{j as e}from"./vendor-Dh_dlHsl.js";import{C as t,A as s,E as i,P as o,N as a,W as n}from"./subject-01-thinking-in-agents-BIrOrpH9.js";const k={id:"tools",title:"Tools — Extending Agent Capabilities",description:"Tools transform language models from thinkers into doers. Learn to design, compose, and manage the capabilities agents rely on.",icon:"🔧",colorHex:"#0891b2",difficulty:"beginner",estimatedHours:10,prerequisites:["thinking-in-agents"],chapters:[{id:"c1-philosophy-of-tools",title:"The Philosophy of Tools",description:"Why tools exist and what makes them effective for agents.",difficulty:"beginner",estimatedMinutes:80,sections:[{id:"s1-why-tools",title:"Why Language Models Need Tools",description:"The fundamental limitation of text generation and how tools bridge the gap.",difficulty:"beginner",readingMinutes:10},{id:"s2-good-tool",title:"What Makes a Good Tool",description:"Atomic, predictable, observable — the three qualities of effective agent tools.",difficulty:"beginner",readingMinutes:12},{id:"s3-tool-categories",title:"Categories of Tools",description:"Reading, writing, executing, searching, and communicating — the five families.",difficulty:"beginner",readingMinutes:10},{id:"s4-tool-contract",title:"The Tool as a Contract",description:"Inputs, execution, outputs, and side effects — the promises a tool makes.",difficulty:"beginner",readingMinutes:10}]},{id:"c2-tool-design",title:"Tool Design Principles",description:"How to design tools that agents can discover, understand, and use correctly.",difficulty:"intermediate",estimatedMinutes:100,sections:[{id:"s1-naming-description",title:"Naming and Description",description:"How agents discover what is available — the importance of clear tool metadata.",difficulty:"beginner",readingMinutes:10},{id:"s2-input-schemas",title:"Input Schemas",description:"Guiding correct tool usage through structured, typed parameters.",difficulty:"intermediate",readingMinutes:12},{id:"s3-output-design",title:"Output Design",description:"Crafting results an agent can reason about — structured, concise, actionable.",difficulty:"intermediate",readingMinutes:10},{id:"s4-idempotency",title:"Idempotency",description:"Why repeating a tool call should be safe and how to design for it.",difficulty:"intermediate",readingMinutes:10},{id:"s5-granularity",title:"Granularity — One Tool, One Job",description:"The right level of abstraction — neither too broad nor too narrow.",difficulty:"intermediate",readingMinutes:10}]},{id:"c3-tool-composition",title:"Tool Selection and Composition",description:"How agents choose, chain, and compose tools to accomplish complex tasks.",difficulty:"intermediate",estimatedMinutes:100,sections:[{id:"s1-choosing-right-tool",title:"How an Agent Chooses the Right Tool",description:"The decision process behind tool selection — matching capability to intent.",difficulty:"intermediate",readingMinutes:10},{id:"s2-sequential-composition",title:"Sequential Composition",description:"When order creates meaning — tools that must run one after another.",difficulty:"intermediate",readingMinutes:10},{id:"s3-parallel-composition",title:"Parallel Composition",description:"When independence enables speed — running multiple tools simultaneously.",difficulty:"intermediate",readingMinutes:10},{id:"s4-tool-chaining",title:"Tool Chaining",description:"Output of one tool becomes input of another — building pipelines of action.",difficulty:"intermediate",readingMinutes:10},{id:"s5-graceful-failure",title:"Graceful Failure",description:"What happens when a tool breaks and how agents should recover.",difficulty:"intermediate",readingMinutes:12}]}]};function r(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("h2",{children:"Why Agents Need Tools"}),e.jsx("p",{children:"A language model, at its core, is a function that takes text in and produces text out. It reasons, it synthesizes, it infers — but everything happens inside that boundary. The world, however, does not live in text. Prices change, files get updated, APIs respond, databases grow. To act meaningfully in the world, an agent must reach beyond language. That reaching is what tools are for."}),e.jsx(t,{title:"What a Tool Is",number:"Concept 2.1",children:"A tool is a named, callable capability that an agent can invoke to interact with something outside its own reasoning process. Tools bridge the gap between the agent's internal world of language and the external world of state, computation, and real effects. Without tools, an agent can only describe the world. With tools, it can change it."}),e.jsx("p",{children:"Think about what makes a human expert effective. A doctor does not diagnose from pure memory alone — they order tests, check lab results, consult imaging. An engineer does not design in their head only — they run simulations, inspect materials, measure tolerances. Expertise is the ability to direct external instruments intelligently. The same is true for agents."}),e.jsx(s,{title:"The Surgeon's Instruments",children:"A surgeon's skill is not in their hands alone but in their mastery of when and how to use each instrument. A scalpel, a clamp, a suture — each has a precise purpose. Using the wrong instrument, or using the right one at the wrong moment, causes harm. The surgeon's judgment about which tool to reach for, and when to hold back, is the real expertise. An agent's relationship to its tools is the same."}),e.jsx("h3",{children:"The Fundamental Limitation Tools Solve"}),e.jsxs("p",{children:["Language models have a knowledge cutoff. They cannot see what happened after training ended. They cannot read a specific file on a specific server. They cannot check whether an order has shipped or a payment has cleared. This is not a flaw to be fixed — it is the nature of the architecture. Tools are the designed solution: the agent reasons about ",e.jsx("em",{children:"what to do"}),", and tools carry those intentions into reality."]}),e.jsx("p",{children:"Tools also enable verification. An agent that can only reason may hallucinate facts with confidence. An agent that can query a real database, call a real API, or read a real file can ground its reasoning in verified state. This is one of the most important properties tools bring to agents: they introduce a reality check into the reasoning loop."}),e.jsx(i,{title:"Why Tools Matter",exercises:[{id:"wt-1",difficulty:"beginner",question:"Name three categories of tasks that are impossible for a tool-less agent but become possible once tools are added. For each, explain what specific limitation the tool overcomes.",hint:"Think about time (cutoff), state (external systems), and computation (precise calculation).",solution:"Examples: (1) Real-time data lookup — overcomes the knowledge cutoff by fetching live information. (2) File manipulation — overcomes the text-only boundary by reading/writing persistent state. (3) Exact arithmetic or computation — overcomes probabilistic reasoning by delegating to deterministic execution."},{id:"wt-2",difficulty:"intermediate",question:"An agent is asked to summarize a customer's order history. Without tools, how would it respond, and what are the risks? With a database query tool, how does the situation change?",hint:'Consider what the agent "knows" versus what it can "verify".',solution:"Without tools, the agent can only describe a generic process or fabricate plausible-sounding data — a serious hallucination risk in a business context. With a database query tool, the agent retrieves actual records and grounds its summary in verified facts, making the response both accurate and auditable."},{id:"wt-3",difficulty:"intermediate",question:'Why is the distinction between "describing an action" and "performing an action" important when thinking about what tools enable?',hint:"Think about the difference between telling someone how to send an email versus actually sending it.",solution:"Describing an action has no real-world effect — it is pure language. Performing an action changes state in the world: a file is written, a message is sent, a record is updated. Tools collapse the gap between these two, which is powerful but also means the agent now bears responsibility for real consequences. This is why tool design and invocation judgment both matter enormously."}]})]})}const j=Object.freeze(Object.defineProperty({__proto__:null,default:r},Symbol.toStringTag,{value:"Module"}));function l(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("h2",{children:"What Makes a Good Tool"}),e.jsx("p",{children:"Not all tools are created equal. A poorly designed tool can confuse an agent, produce unreliable results, or create dangerous side effects that are difficult to reverse. A well-designed tool does the opposite: it is predictable, honest about its capabilities, and easy for the agent to reason about. The quality of a tool shapes the quality of every agent that uses it."}),e.jsx(o,{title:"Tools Should Do One Thing Well",number:"Principle 2.1",children:"A good tool has a single, clearly bounded responsibility. It does not try to be clever or combine multiple concerns. When a tool's scope is narrow and its behavior is predictable, the agent can reason about it accurately — including when not to use it. Overloaded tools breed confusion and error."}),e.jsx("h3",{children:"The Properties That Matter"}),e.jsx("p",{children:"Good tools share a cluster of properties that make them trustworthy partners in the agent's reasoning loop:"}),e.jsxs("ul",{children:[e.jsxs("li",{children:[e.jsx("strong",{children:"Clarity:"})," The tool's name and description tell the agent exactly what it does and when to use it. There is no ambiguity about its purpose."]}),e.jsxs("li",{children:[e.jsx("strong",{children:"Predictability:"})," Given the same inputs, a good tool behaves consistently. The agent can build reliable mental models about its behavior."]}),e.jsxs("li",{children:[e.jsx("strong",{children:"Honesty:"})," A good tool accurately reports success, failure, and partial results. It does not silently swallow errors or return misleading outputs."]}),e.jsxs("li",{children:[e.jsx("strong",{children:"Safety:"})," A good tool makes it difficult to cause accidental harm. Destructive operations are clearly marked. Irreversible actions require confirmation."]})]}),e.jsx(t,{title:"Tool Trustworthiness",number:"Concept 2.2",children:"An agent's trust in a tool is built through consistent, honest behavior over time. A tool that sometimes silently fails, sometimes returns stale data, or sometimes interprets its inputs loosely destroys the agent's ability to reason reliably. Trust is not a nice-to-have — it is the foundation of the entire tool-agent relationship. Untrustworthy tools produce untrustworthy agents."}),e.jsx("h3",{children:"The Problem of Silent Failure"}),e.jsx("p",{children:"One of the most dangerous failure modes in tool design is silent failure: the tool appears to succeed but either did nothing or did something wrong. When a tool silently fails, the agent has no signal to reconsider its plan. It continues onward, building further actions on a false foundation. By the time the error surfaces — if it surfaces at all — the agent may be many steps deep into a broken workflow."}),e.jsx("p",{children:"Good tools fail loudly. They surface errors explicitly, describe what went wrong, and give the agent the information it needs to adapt. A loud failure is a recoverable failure. A silent one often is not."}),e.jsx(a,{title:"Honesty Over Convenience",type:"tip",children:'It can be tempting to design tools that "do their best" and return something even when the request cannot be properly fulfilled. Resist this temptation. An agent that receives a partial or fabricated result will reason as if it received a real one. Honest error reporting — even when it means returning nothing — is always the better choice.'}),e.jsx(i,{title:"Properties of Good Tools",exercises:[{id:"gt-1",difficulty:"beginner",question:'Consider a tool called "get_data" that can search a database, read a file, or call an external API depending on a mode parameter. What problems might this cause for an agent trying to use it?',hint:"Think about predictability and the mental model the agent needs to form.",solution:"The agent must understand three different behaviors from one tool, which increases the risk of misuse. The mode parameter adds decision complexity. Error messages become ambiguous. The tool's description cannot be concise. Splitting into three separate, focused tools (search_database, read_file, call_api) is almost always superior."},{id:"gt-2",difficulty:"intermediate",question:"A tool is designed to send an email. When the recipient address is invalid, it silently discards the message and returns a success response. Trace the chain of problems this causes in an agent workflow.",hint:"Follow the agent's reasoning after it believes the email was sent.",solution:"The agent believes the email succeeded. It may mark the task complete, move to the next step, or report success to the user. The intended recipient never receives the message, but no one knows. The user may wait indefinitely for a reply. Debugging is extremely difficult because all logs show success. The fix is simple: return a clear error when the address is invalid."},{id:"gt-3",difficulty:"advanced",question:'How does the concept of "tool trustworthiness" relate to the reliability of agents built on top of those tools? Can a trustworthy agent be built from untrustworthy tools?',hint:"Think about how errors propagate through a reasoning chain.",solution:"No — agent reliability is bounded by the reliability of its tools. Each tool invocation is a point where external reality enters the agent's reasoning. If that entry point is noisy, inconsistent, or dishonest, all downstream reasoning is built on a flawed foundation. You can add error-handling logic, but you cannot fully compensate for a tool that lies about its outputs. Trustworthy agents require trustworthy tools as a prerequisite."}]})]})}const q=Object.freeze(Object.defineProperty({__proto__:null,default:l},Symbol.toStringTag,{value:"Module"}));function h(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("h2",{children:"Categories of Tools"}),e.jsx("p",{children:"Tools are not a monolithic category. They differ dramatically in what they do, what they touch, and what risks they carry. Understanding the natural categories of tools helps agents — and their designers — reason about which tools are appropriate in a given context, and what safeguards each category demands."}),e.jsx(t,{title:"Read vs. Write Tools",number:"Concept 2.3",children:"The most fundamental distinction in tool classification is between tools that observe the world and tools that change it. Read tools retrieve information without side effects — they are inherently safer to invoke speculatively. Write tools modify state — files, databases, messages, external services — and carry real-world consequences. This distinction determines how much caution an agent should exercise before invoking a tool."}),e.jsx("h3",{children:"A Taxonomy of Tool Categories"}),e.jsxs("ul",{children:[e.jsxs("li",{children:[e.jsx("strong",{children:"Information retrieval:"})," Fetch facts, data, or documents from external sources. These are read-only and safe to retry. Examples: web search, database queries, file reads, API lookups."]}),e.jsxs("li",{children:[e.jsx("strong",{children:"Computation:"})," Perform calculations or transformations that the agent cannot reliably do through language alone. These are deterministic and side-effect-free. Examples: arithmetic, unit conversion, data parsing, regex matching."]}),e.jsxs("li",{children:[e.jsx("strong",{children:"State mutation:"})," Create, update, or delete persistent state somewhere in the world. These are consequential and often irreversible. Examples: writing files, inserting database records, updating configuration."]}),e.jsxs("li",{children:[e.jsx("strong",{children:"Communication:"})," Send messages or notifications to other agents, systems, or people. Once sent, these cannot be unsent. Examples: email, webhooks, push notifications, API calls that trigger downstream processes."]}),e.jsxs("li",{children:[e.jsx("strong",{children:"Delegation:"})," Hand off a task to another agent or subprocess. These tools multiply the agent's capabilities but also amplify any errors in its judgment. Examples: spawning subagents, calling specialized models, invoking pipelines."]})]}),e.jsx("h3",{children:"Why Categories Shape Risk"}),e.jsx("p",{children:"Each category carries a different risk profile. Information retrieval tools can be retried freely — if one fails, the agent asks again. Computation tools are deterministic and reversible in effect (the world is unchanged). But state mutation and communication tools carry lasting consequences. A mistaken file deletion or a prematurely sent email cannot be automatically undone."}),e.jsx("p",{children:"Agents should apply proportional caution: more deliberation before write operations, explicit confirmation before irreversible communication, and careful scoping before delegation. The category a tool belongs to is a signal about the level of care required before invoking it."}),e.jsx(a,{title:"Reversibility as a First Principle",type:"intuition",children:`When evaluating how carefully to use a tool, ask: "If this invocation is wrong, can it be undone?" Read tools can always be retried. Computation leaves no mark. But writes and sends are often permanent. Reversibility is not the only consideration, but it is the most important one for calibrating an agent's caution before it acts.`}),e.jsx(i,{title:"Tool Categories in Practice",exercises:[{id:"tc-1",difficulty:"beginner",question:"Classify each of the following tools into one of the five categories: (a) a tool that looks up a customer record by ID, (b) a tool that converts a temperature from Celsius to Fahrenheit, (c) a tool that posts a message to a Slack channel, (d) a tool that assigns a sub-task to a specialized research agent.",hint:"Focus on whether each tool reads, computes, mutates, communicates, or delegates.",solution:"(a) Information retrieval — reads a record without side effects. (b) Computation — deterministic transformation with no side effects. (c) Communication — sends an irreversible message to external parties. (d) Delegation — hands off work to another agent."},{id:"tc-2",difficulty:"intermediate",question:'An agent has both a "search_web" tool and a "send_email" tool. A user asks it to "research the top competitors and send me a summary." Why might the agent treat these two tools very differently, even within a single workflow?',hint:"Consider what happens if the agent makes a mistake with each tool.",solution:"A mistake with search_web is harmless — the agent can retry with different terms, and no external state is changed. A mistake with send_email cannot be undone. The agent should invest more care in verifying the email content is accurate and complete before sending. It might also want to confirm with the user before committing to the irreversible communication step."},{id:"tc-3",difficulty:"advanced",question:"Delegation tools are described as both capability-multiplying and error-amplifying. Explain what this means and how an agent designer should account for it.",hint:"Think about how a wrong premise passed to a subagent compounds through that subagent's actions.",solution:"Delegation multiplies capability because the subagent can do things the parent cannot do alone. But if the parent agent passes incorrect context or a flawed instruction, the subagent acts on that flaw — potentially taking many consequential actions before the error surfaces. The wrong premise is amplified through all downstream tool calls the subagent makes. Designers should ensure delegation tools include clear scope boundaries, require explicit task descriptions, and surface subagent outcomes back to the parent for review before irreversible consequences are triggered."}]})]})}const A=Object.freeze(Object.defineProperty({__proto__:null,default:h},Symbol.toStringTag,{value:"Module"}));function c(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("h2",{children:"The Tool Contract"}),e.jsx("p",{children:"Every tool embodies an implicit agreement between the tool designer and the agents that use it. This agreement — the tool contract — defines what the tool promises to do, what it requires in return, and how it will behave when things go wrong. When this contract is clear and honored, agents can reason confidently. When it is vague or violated, agents fail in ways that are hard to diagnose and harder to fix."}),e.jsx(t,{title:"The Tool Contract",number:"Concept 2.4",children:"A tool contract has three parts. The precondition defines what must be true for the tool to operate correctly — valid inputs, required permissions, necessary state. The postcondition defines what will be true after a successful invocation — what changed, what was returned, what can be relied upon. The invariant defines what the tool will never do — what it will not touch, what it will not break, regardless of inputs. Together these three parts define the boundary of safe use."}),e.jsx("h3",{children:"Why Contracts Matter for Agents"}),e.jsx("p",{children:"Human developers can read documentation, ask colleagues, and run experiments to understand how a tool behaves. Agents primarily learn from the tool's name, description, and schema. If those signals are incomplete or misleading, the agent cannot reason correctly about whether to invoke the tool, what inputs to provide, or what to do with the result."}),e.jsx("p",{children:"The tool contract is not just internal documentation — it is the agent's primary interface to understanding what the tool does. A well-specified contract allows an agent to plan accurately. A missing or broken contract forces the agent to guess. Guessing in a tool-invocation context has real-world consequences."}),e.jsx(o,{title:"Honor the Contract Completely",number:"Principle 2.2",children:"A tool that violates its own contract is more dangerous than a tool that fails outright. When a tool fails, the agent knows something went wrong. When a tool silently violates its postconditions — modifying state it said it would not touch, returning results that do not reflect its stated behavior — the agent reasons confidently on false ground. Contract violations are the hardest bugs to find and fix."}),e.jsx("h3",{children:"Specifying Good Preconditions"}),e.jsx("p",{children:"Preconditions should be stated explicitly in the tool's description: what inputs are required, what format they must be in, what assumptions the tool makes about the state of the world when it is called. The more precisely a precondition is stated, the better the agent can determine whether calling the tool right now is appropriate."}),e.jsx("p",{children:"A tool that fails silently when preconditions are violated is dangerous. A tool that checks its preconditions and returns a clear error when they are not met is safe. The agent receives honest information and can adapt its plan accordingly."}),e.jsx(n,{title:"Partial Contracts Are Contract Violations",children:`A tool description that says "retrieves user data" but does not specify what happens when the user does not exist, when permissions are insufficient, or when the service is unavailable is a partial contract. The agent will guess about these cases — and often guess wrong. Every significant edge case in a tool's behavior deserves explicit treatment in its contract.`}),e.jsx(i,{title:"Understanding Tool Contracts",exercises:[{id:"tc-c-1",difficulty:"beginner",question:'For a hypothetical "delete_file" tool, specify: (a) two preconditions the tool should check, (b) two postconditions that should hold after successful execution, and (c) one invariant — something the tool must never do regardless of inputs.',hint:"Think about what must be true before, what must be true after, and what absolute limits the tool must respect.",solution:"(a) Preconditions: the file path must exist and be valid; the calling agent must have write permission to that location. (b) Postconditions: the file no longer exists at that path; any locks or handles held to the file are released. (c) Invariant: the tool must never delete files outside the allowed working directory, regardless of what path is provided."},{id:"tc-c-2",difficulty:"intermediate",question:`An agent receives the result from a "calculate_discount" tool and uses it to generate an invoice. The tool's description says it "applies the correct discount for the customer tier." Later it emerges the tool was applying last year's discount rates. Which part of the contract failed, and what was the downstream consequence?`,hint:"Focus on the postcondition and what the agent assumed was guaranteed.",solution:"The postcondition failed: the tool implied it would return the correct current discount, but actually returned stale data. The agent reasonably assumed the result was accurate and built the invoice on top of it. Every invoice generated in that period was incorrect. The agent had no way to detect this because the tool returned a result without error — a postcondition violation is invisible from the outside."},{id:"tc-c-3",difficulty:"advanced",question:"How does the concept of a tool contract relate to composability? When you chain tools together, what guarantees must each tool's contract provide for the composition to be reliable?",hint:"Think about how one tool's postconditions become the next tool's preconditions.",solution:"In a tool chain, the postconditions of each tool must satisfy the preconditions of the next. If tool A promises to return a validated user ID, and tool B requires a validated user ID, the chain is reliable only if tool A's postcondition guarantee is truly upheld. Any gap between what one tool promises and what the next tool requires is a potential failure point. Reliable composition requires that contracts be precise enough to verify these transitions, not just vague enough to seem compatible."}]})]})}const _=Object.freeze(Object.defineProperty({__proto__:null,default:c},Symbol.toStringTag,{value:"Module"}));function d(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("h2",{children:"Naming and Describing Tools"}),e.jsx("p",{children:"An agent decides whether and how to use a tool primarily from its name and description. Unlike a human developer who can explore documentation, run experiments, and ask for help, an agent must infer the full contract of a tool from the words given to it at invocation time. This makes naming and description the most consequential design decisions in tool creation."}),e.jsx(o,{title:"Names Are Contracts in Miniature",number:"Principle 2.3",children:"A tool's name is the first thing an agent sees and the most memorable signal it carries. A good name communicates the tool's action and its target in a few words — enough that the agent can form an accurate mental model before reading a single word of description. A bad name forces the agent to rely entirely on the description — and descriptions are frequently incomplete."}),e.jsx("h3",{children:"Anatomy of a Good Tool Name"}),e.jsx("p",{children:"Strong tool names follow a consistent pattern: a verb that describes what the tool does, followed by a noun that describes what it acts on. This pattern makes the tool's purpose immediately clear and allows agents to distinguish between related tools without confusion."}),e.jsxs("ul",{children:[e.jsxs("li",{children:[e.jsx("strong",{children:"Action-first:"})," Start with the verb — fetch, search, create, update, delete, send, list."]}),e.jsxs("li",{children:[e.jsx("strong",{children:"Specific nouns:"}),' "get_user_profile" is better than "get_user" — it tells the agent what specifically it retrieves.']}),e.jsxs("li",{children:[e.jsx("strong",{children:"Avoid ambiguity:"}),' "process_data" tells the agent almost nothing. "transform_csv_to_json" tells it exactly what happens.']}),e.jsxs("li",{children:[e.jsx("strong",{children:"Consistent conventions:"})," If most tools use snake_case, all should. Inconsistency increases cognitive load on the agent."]})]}),e.jsx(t,{title:"The Description's Job",number:"Concept 2.5",children:"A tool's description has two responsibilities: it must explain what the tool does when things go right, and it must explain what the tool does when things go wrong. Descriptions that only cover the happy path leave the agent without guidance for the majority of real-world situations, which rarely go exactly as planned. A description should be a concise but complete specification, not a marketing statement."}),e.jsx("h3",{children:"What a Good Description Includes"}),e.jsx("p",{children:"A useful tool description answers these questions explicitly:"}),e.jsxs("ul",{children:[e.jsx("li",{children:"What does this tool do in plain terms?"}),e.jsx("li",{children:"When should an agent prefer this tool over alternatives?"}),e.jsx("li",{children:"What are the important constraints on its use?"}),e.jsx("li",{children:"What does it return on success?"}),e.jsx("li",{children:"What does it return (or what error does it raise) on failure?"})]}),e.jsx("p",{children:"Descriptions that read like bureaucratic documentation — covering everything vaguely and nothing specifically — are worse than shorter descriptions that cover the essential cases precisely. Agents do not benefit from length; they benefit from clarity."}),e.jsx(a,{title:"Descriptions Are Read at Decision Time",type:"tip",children:`The agent reads a tool's description when it is deciding whether to call that tool. Every word the agent must parse is cognitive overhead. Write descriptions that are dense with useful signal, not padded with phrases like "this tool is designed to allow you to..." Get to the point immediately: what it does, when to use it, and what to expect.`}),e.jsx(i,{title:"Naming and Describing Tools",exercises:[{id:"nd-1",difficulty:"beginner",question:'Rank these tool names from best to worst and explain your reasoning: "do_thing", "process", "send_invoice_email", "email_tool", "communicate".',hint:"Evaluate each name on: does it convey the action, the target, and the scope?",solution:'Best to worst: (1) "send_invoice_email" — precise verb, precise noun, clear scope. (2) "email_tool" — identifies the domain but lacks an action. (3) "communicate" — too vague: is it email? SMS? Chat? (4) "process" — completely undescribed action with no target. (5) "do_thing" — conveys nothing at all.'},{id:"nd-2",difficulty:"intermediate",question:"Write a two-sentence description for a tool that searches a product catalog by keyword. The first sentence should cover the happy path; the second should cover what happens when no results are found or the query is invalid.",hint:"The happy path needs to specify what is returned. The failure path needs to specify what signal the agent receives.",solution:'Example: "Searches the product catalog and returns a list of matching items including name, SKU, price, and availability, ordered by relevance. Returns an empty list when no products match the query; returns an error if the query string is blank or exceeds 200 characters."'},{id:"nd-3",difficulty:"advanced",question:'An agent toolset has these two tools: "get_record" and "fetch_data". Both retrieve information from different sources. What problems does this naming create, and how would you fix it?',hint:"Think about how the agent must distinguish between them and what information it lacks.",solution:'The agent cannot tell from the names alone what source each tool accesses, what kind of record or data is involved, or when to prefer one over the other. Both names are ambiguous. Fixes: rename to reflect both the action and the target source — for example, "get_customer_profile_from_crm" and "fetch_transaction_log_from_warehouse". The agent can now make accurate tool-selection decisions without having to memorize descriptions.'}]})]})}const I=Object.freeze(Object.defineProperty({__proto__:null,default:d},Symbol.toStringTag,{value:"Module"}));function u(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("h2",{children:"Designing Input Schemas"}),e.jsx("p",{children:"A tool's input schema is the formal specification of what the tool expects to receive. For agents, this schema serves as both a guide and a guardrail: it tells the agent how to construct a valid invocation, and it prevents malformed inputs from reaching the tool's internals. Schema design is one of the most precision-sensitive tasks in tool engineering — small choices here have large consequences downstream."}),e.jsx(t,{title:"Schemas as Executable Contracts",number:"Concept 2.6",children:"Unlike a description, which is prose that the agent reads and interprets, an input schema is a formal structure that is enforced at runtime. If the agent provides the wrong type or omits a required field, the schema rejects the call before execution begins. This makes schemas the last line of defense against malformed invocations — and the first place an agent can receive concrete feedback about what it got wrong."}),e.jsx("h3",{children:"Field Design Principles"}),e.jsx("p",{children:"Each field in an input schema is a commitment. Design them to be as specific as necessary and as permissive as safely possible:"}),e.jsxs("ul",{children:[e.jsxs("li",{children:[e.jsx("strong",{children:"Choose the narrowest type that works:"})," If a field should always be a positive integer, say so. Do not accept strings and validate internally — reject invalid types at the schema level where the feedback is immediate and structured."]}),e.jsxs("li",{children:[e.jsx("strong",{children:"Mark fields required or optional deliberately:"})," Optional fields with defaults should have those defaults stated explicitly. An agent must know whether omitting a field changes the tool's behavior, and how."]}),e.jsxs("li",{children:[e.jsx("strong",{children:"Describe each field:"}),' Every field deserves a one-line description that explains its purpose and any constraints. A field named "limit" without a description leaves the agent guessing whether it means a count, a size in bytes, or a time limit.']}),e.jsxs("li",{children:[e.jsx("strong",{children:"Use enumerations for constrained choices:"})," If a parameter accepts only specific values, list them as an enumeration. This prevents the agent from inventing plausible-but-invalid values."]})]}),e.jsx(o,{title:"Be Strict at the Boundary",number:"Principle 2.4",children:"Input validation should happen as early as possible — at the schema level, not deep inside the tool's logic. An input that fails at the boundary gives the agent an immediate, structured signal about what to correct. An input that passes schema validation but fails inside the tool gives the agent a confusing error that is harder to act on. Push validation outward, toward the interface."}),e.jsx("h3",{children:"The Danger of Overly Permissive Schemas"}),e.jsx("p",{children:"Accepting too much is as dangerous as accepting too little. A schema that accepts any string for a field that should be a date allows the agent to pass malformed values that the tool must then interpret. This interpretation is where silent failures and unexpected behavior are born. A schema that accepts only strings matching a specific date format eliminates an entire class of bugs before they can occur."}),e.jsx(n,{title:"Do Not Accept What You Cannot Handle",children:'A common mistake is designing schemas that accept broad inputs "for flexibility" and then relying on internal logic to handle edge cases. Every edge case your schema accepts is an obligation you must fulfill in code. Permissive schemas create silent obligations. Narrow schemas make obligations explicit. Default to strict, and only loosen when there is a clear and justified need.'}),e.jsx(i,{title:"Input Schema Design",exercises:[{id:"is-1",difficulty:"beginner",question:'A tool searches for users by status. The "status" parameter currently accepts any string. What problems does this create, and how would you improve the schema for this parameter?',hint:"Think about what values are actually valid and what happens when an invalid value is passed.",solution:'Accepting any string means an agent could pass "actve" (typo), "ACTIVE" (wrong case), or "online" (wrong vocabulary). The tool must then decide how to handle each case — silently normalize, silently fail, or error inconsistently. The fix is to declare status as an enumeration with the valid values explicitly listed (e.g., ["active", "inactive", "pending"]). The agent is guided to correct values, and invalid inputs are rejected at the boundary.'},{id:"is-2",difficulty:"intermediate",question:"You are designing a tool that fetches a paginated list of records. What fields would you include in the input schema, and for each, what type, constraints, and description would you specify?",hint:"Think about what information the tool needs: what to fetch, how many, and where in the list to start.",solution:'Suggested schema: (1) "query" — string, required, max 500 chars, "The search terms to filter records by." (2) "page" — integer, optional, default 1, minimum 1, "The page number to retrieve, starting from 1." (3) "page_size" — integer, optional, default 20, minimum 1, maximum 100, "Number of records per page." Each constraint is justified: query length prevents abuse, page minimum prevents invalid pages, page_size maximum prevents overloading the backend.'},{id:"is-3",difficulty:"advanced",question:'Consider a tool whose schema has evolved over time: it now has 12 input fields, most of which are optional with complex interdependencies (field C is only relevant when field A is set to "advanced" mode). What design problem has occurred, and how would you address it?',hint:"Think about what happens to an agent's ability to reason about correct invocation as a schema grows in complexity.",solution:'The schema has accumulated complexity that the agent must model entirely in its head. Interdependent optional fields create an exponential space of valid and invalid combinations that cannot be fully captured in standard type schemas. The design problem is conflation: the tool is trying to serve multiple distinct use cases. The solution is usually to split into separate tools by mode ("run_basic_analysis" vs "run_advanced_analysis"), each with its own clean, independent schema. Alternatively, a single required "mode" field can serve as a top-level discriminator with clearly scoped sub-schemas for each mode.'}]})]})}const C=Object.freeze(Object.defineProperty({__proto__:null,default:u},Symbol.toStringTag,{value:"Module"}));function p(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("h2",{children:"Designing Tool Outputs"}),e.jsx("p",{children:"The output of a tool is what the agent has to work with next. An agent cannot see inside a tool — it only observes what the tool returns. If that return value is ambiguous, incomplete, or structured in a way that is difficult to reason about, the agent's next step is compromised before it begins. Output design is not an afterthought; it shapes every downstream decision the agent makes."}),e.jsx(t,{title:"Outputs Are the Agent's Reality",number:"Concept 2.7",children:"After a tool invocation, the agent's model of the world is updated by what the tool returns. The output becomes the agent's ground truth for that piece of the world. If the output is misleading — success reported when nothing happened, data returned without indicating it is stale, an error message that describes symptoms rather than causes — the agent's model of reality diverges from actual reality. Divergence accumulates silently until it becomes a visible failure."}),e.jsx("h3",{children:"The Structure of a Good Output"}),e.jsx("p",{children:"Well-designed tool outputs share several properties:"}),e.jsxs("ul",{children:[e.jsxs("li",{children:[e.jsx("strong",{children:"Explicit success/failure signaling:"})," The agent should never have to infer whether a call succeeded. Success and failure should be unambiguous, structured, and immediately distinguishable."]}),e.jsxs("li",{children:[e.jsx("strong",{children:"Complete enough to act on:"})," The agent should not need to call the same tool again to get information it needed in the first place. Outputs should anticipate what the agent will want to do next and provide the relevant context."]}),e.jsxs("li",{children:[e.jsx("strong",{children:"Minimal enough to be clear:"})," Returning everything a tool knows is not always helpful. Irrelevant data adds noise that the agent must filter, which increases the chance of misinterpretation. Return what is needed for the task, not a data dump."]}),e.jsxs("li",{children:[e.jsx("strong",{children:"Consistent structure:"})," Success and failure responses should use consistent field names and structures. An agent that must parse different shapes of output for different outcomes is prone to parsing errors."]})]}),e.jsx(o,{title:"Error Outputs Are First-Class",number:"Principle 2.5",children:'Error responses deserve as much design attention as success responses. A good error output tells the agent what went wrong, why it went wrong, and — whenever possible — what the agent should try instead. An error that says only "failed" is nearly useless. An error that says "record not found: the provided ID does not exist in this database" gives the agent everything it needs to adapt its plan.'}),e.jsx("h3",{children:"Handling Partial Results"}),e.jsx("p",{children:"Some tools can partially succeed: they complete some of what was requested but not all. A batch operation might process eight records successfully before failing on the ninth. Partial results require explicit handling in the output design. The agent must know: how much succeeded, how much failed, and whether the partial success is usable or should be rolled back."}),e.jsx("p",{children:"Returning a partial result without signaling its partiality is one of the most treacherous output design mistakes. The agent assumes it received the full result and acts accordingly — planning, reporting, or triggering downstream actions based on incomplete data."}),e.jsx(a,{title:"Think About the Receiving Agent",type:"intuition",children:`When designing a tool's output, ask: "What will the agent try to do with this response?" Design the output to make that next action easy and safe. If the agent will likely need to check whether to retry, include retry guidance. If it will need to present results to a user, ensure the output contains human-readable summaries. The best outputs are shaped by the expected downstream action, not by internal data structures.`}),e.jsx(i,{title:"Tool Output Design",exercises:[{id:"od-1",difficulty:"beginner",question:"A file-writing tool currently returns the number of bytes written on success, and an empty string on failure. What is wrong with this design, and how would you improve both the success and failure responses?",hint:"Think about what information the agent actually needs after a write operation, and what it needs when the write fails.",solution:'The success response is technically informative but incomplete — the agent does not know the final path, whether the file was created or overwritten, or when it was written. The failure response ("") is a silent failure: the agent cannot distinguish failure from success easily, and receives no information about what went wrong. Improved design: success returns the full path, file size, and timestamp of the write. Failure returns a structured error with a code (e.g., "permission_denied", "disk_full") and a human-readable explanation.'},{id:"od-2",difficulty:"intermediate",question:'An agent calls a "send_bulk_notifications" tool with 50 recipients. The tool sends successfully to 43 and fails for 7 due to invalid addresses. How should the tool structure its output to give the agent an accurate picture of what happened?',hint:"The agent needs to know what succeeded, what failed, and enough detail to decide what to do about the failures.",solution:'The output should include: a top-level status field indicating partial success (not simply "success" or "failure"), a count and list of successfully notified recipients, and a separate list of failed recipients with the specific reason for each failure (e.g., "invalid email format" or "address bounced"). This allows the agent to report accurate results to the user, flag the failed addresses for correction, and decide whether to retry or escalate without needing to call any additional tools.'},{id:"od-3",difficulty:"advanced",question:'Why might returning "too much" data from a tool be just as harmful as returning too little? Describe a concrete scenario where an over-verbose tool output leads to agent error.',hint:"Consider how agents process and prioritize information within their context window.",solution:"Agents have finite context and must reason over everything they receive. An over-verbose output — for example, a tool that returns an entire database record with 80 fields when the agent only needed the user's email — floods the agent's context with noise. The agent must now parse, evaluate, and carry this weight forward through subsequent reasoning steps. In practice, agents may lose track of the key fields, mis-prioritize information, or simply exceed context limits and start dropping earlier context. A tool that returns only the three fields the task requires produces faster, more accurate downstream reasoning."}]})]})}const S=Object.freeze(Object.defineProperty({__proto__:null,default:p},Symbol.toStringTag,{value:"Module"}));function f(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("h2",{children:"Idempotency and Safe Retries"}),e.jsx("p",{children:"Agents operate in unreliable environments. Networks drop connections. Services time out. Tools return ambiguous results that leave the agent unsure whether its call succeeded. In these moments, the agent faces a fundamental question: is it safe to try again? The answer depends almost entirely on whether the tool is idempotent."}),e.jsx(t,{title:"Idempotency",number:"Concept 2.8",children:'A tool is idempotent if calling it multiple times with the same inputs produces the same result as calling it once. The world ends up in the same state whether the tool was called one time or ten. Idempotency is not about returning the same value on every call — it is about not accumulating side effects. An idempotent "set status to active" is safe to retry. A non-idempotent "increment counter" is not.'}),e.jsx("h3",{children:"Why Idempotency Matters for Agents"}),e.jsx("p",{children:"An agent that is uncertain whether its last tool call succeeded has two options: assume success and move on, or retry and risk double-execution. Both options are dangerous if the tool is not idempotent. Assume success and you may skip a required step. Retry and you may send the email twice, charge the card twice, or create the record twice."}),e.jsx("p",{children:"Idempotent tools eliminate this dilemma. When an agent is uncertain, it can retry safely. If the first call succeeded, the retry produces no additional effect. If it failed, the retry completes the work. The agent can recover from network ambiguity without risk of duplication."}),e.jsx(s,{title:"The Elevator Button",children:"Pressing an elevator button is idempotent. Press it once, the elevator is summoned. Press it five more times because you are impatient — the elevator still comes once, and arrives at the same time. The button was designed so that repeated presses have no additional effect beyond the first. Good tool design works the same way: the agent should be able to press the button as many times as it needs without fear of summoning five elevators."}),e.jsx(o,{title:"Design for the Retry Case",number:"Principle 2.6",children:'When designing a tool, the retry scenario should be a primary design consideration — not an edge case. Ask explicitly: "What happens if this tool is called twice with the same inputs?" If the answer is "bad things," the tool needs to be redesigned or wrapped with deduplication logic before it is safe for agent use. Tools that are designed without considering retries become ticking time bombs in production agents.'}),e.jsx("h3",{children:"Techniques for Achieving Idempotency"}),e.jsx("p",{children:"Not all operations are naturally idempotent, but most can be made idempotent through careful design:"}),e.jsxs("ul",{children:[e.jsxs("li",{children:[e.jsx("strong",{children:"Upsert instead of insert:"})," An operation that creates a record if it does not exist, and updates it if it does, is idempotent. A pure insert that fails or duplicates on re-run is not."]}),e.jsxs("li",{children:[e.jsx("strong",{children:"Idempotency keys:"})," The agent provides a unique identifier with each request. The tool checks whether that identifier has been processed before. If yes, it returns the stored result. If no, it processes and stores the result for future retries."]}),e.jsxs("li",{children:[e.jsx("strong",{children:"Conditional operations:"}),' "Set the status to X only if it is currently Y" naturally limits the effect of retries once the state has been changed.']}),e.jsxs("li",{children:[e.jsx("strong",{children:"Explicit deduplication windows:"})," Some operations (like sending a notification) can suppress duplicates if a matching request was seen within a recent time window."]})]}),e.jsx(i,{title:"Idempotency in Practice",exercises:[{id:"id-1",difficulty:"beginner",question:"Classify each of these operations as idempotent or non-idempotent: (a) set a user's email address, (b) append a line to a log file, (c) place an order for a product, (d) check whether a file exists.",hint:"Ask for each: if you do this twice with identical inputs, does the world end up in a different state than if you did it once?",solution:"(a) Idempotent — setting an email to the same value twice leaves it at that value. (b) Non-idempotent — appending twice adds two lines. (c) Non-idempotent — placing the same order twice creates two orders. (d) Idempotent — checking whether a file exists has no side effects and returns the same result each time."},{id:"id-2",difficulty:"intermediate",question:"An agent sends a payment request via a tool. The network times out and the agent does not know if the payment went through. Without idempotency, what are the two bad outcomes possible? How does an idempotency key solve both problems?",hint:"Think about what happens in each case: the payment did go through, and the payment did not go through.",solution:"If the payment went through and the agent retries: the customer is charged twice. If the payment did not go through and the agent assumes success: the transaction never completes and the service is never rendered. An idempotency key solves both: the payment provider records the key on the first successful attempt. If the agent retries with the same key, the provider returns the original result (already succeeded) rather than processing again. If the key has not been recorded, the payment is processed normally. In both cases, the agent gets an accurate, definitive answer safely."},{id:"id-3",difficulty:"advanced",question:"Some operations are intrinsically non-idempotent (for example, generating a unique invoice number or sending a time-sensitive alert). How should a tool designer expose these tools to agents so that the non-idempotency is clear and safe retries are still possible?",hint:"Think about what information needs to flow between the first attempt and any retry, and how the contract communicates the risk.",solution:`The tool's description should explicitly state it is non-idempotent and what the consequences of a retry are. The tool should return a unique identifier for each successful invocation (e.g., invoice number, notification ID) so the agent can check whether a prior call succeeded before retrying. The agent should be designed to check for this identifier's existence before calling the tool again. For the most sensitive cases, the tool should require the caller to pass an explicit "I understand this is not idempotent" flag, forcing the agent to acknowledge the risk rather than calling it casually.`}]})]})}const W=Object.freeze(Object.defineProperty({__proto__:null,default:f},Symbol.toStringTag,{value:"Module"}));function g(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("h2",{children:"Tool Granularity"}),e.jsx("p",{children:"One of the subtlest decisions in tool design is scope: how much should one tool do? A tool that does too little forces the agent to orchestrate many small steps to accomplish a simple goal. A tool that does too much removes the agent's ability to reason flexibly about what to do at each stage. Getting granularity right is the art of tool design — it requires understanding both the agent's cognitive process and the operational reality of the domain."}),e.jsx(t,{title:"The Granularity Spectrum",number:"Concept 2.9",children:"Tools can be placed on a spectrum from fine-grained (small, single-purpose, composable) to coarse-grained (large, multi-step, opaque). Fine-grained tools give agents maximum flexibility but require more invocations and more coordination. Coarse-grained tools reduce invocation count but hide intermediate state from the agent, making error handling and adaptation harder. Neither extreme is universally correct — the right granularity depends on the task, the failure mode, and the agent's need for visibility."}),e.jsx("h3",{children:"The Cost of Too Fine"}),e.jsx("p",{children:"When tools are too granular, the agent must manage the coordination overhead. A task that could be accomplished in one call now requires a chain of five. Each link in that chain is a potential failure point. The agent must carry intermediate results across steps, track state between calls, and correctly sequence operations. This is not impossible — but it compounds risk and complexity in ways that often outweigh the benefits of flexibility."}),e.jsx("h3",{children:"The Cost of Too Coarse"}),e.jsx("p",{children:'When tools are too coarse-grained, the agent loses visibility into what happened. If a "process entire order" tool fails halfway through, the agent does not know which steps succeeded and which did not. It cannot partially retry, cannot report accurate status, and cannot adapt intelligently. Coarse tools are also harder to test, harder to reason about, and tend to accumulate complexity over time as new edge cases are folded in.'}),e.jsx("p",{children:"Perhaps most importantly, coarse tools undermine the agent's reasoning loop. Agents are designed to plan, act, observe, and adapt. A tool that executes an opaque sequence of ten operations collapses this loop — the agent can no longer observe intermediate state and adapt accordingly. The tool makes decisions the agent should be making."}),e.jsx(o,{title:"Match Granularity to the Failure Surface",number:"Principle 2.7",children:'The right granularity for a tool is often determined by asking: "Where do failures happen, and does the agent need to respond differently to each one?" If every failure in a process requires the same response (abort and report), a coarser tool is fine. If different failures require different recovery strategies, the tool should be split at the points where the response strategy diverges — giving the agent a chance to observe what happened and decide what to do next.'}),e.jsx(a,{title:"The Goldilocks Principle of Tool Design",type:"intuition",children:'The best tools are not so small that the agent drowns in coordination, and not so large that the agent is blind to what happened. A useful heuristic: a tool should complete a logical unit of work that has a single, clear success condition and a small number of distinct failure modes. If you find yourself writing "and then it does X, and then Y, and then Z" in the description, consider splitting.'}),e.jsx(i,{title:"Tool Granularity Decisions",exercises:[{id:"gr-1",difficulty:"beginner",question:"Consider an e-commerce agent that needs to: validate a coupon, calculate the discounted price, apply the discount to the cart, and record the coupon redemption. Should these be one tool or four? Argue both sides.",hint:"Think about what happens if the tool fails midway, and whether the agent needs to respond differently to each failure.",solution:"Case for one tool: it prevents partial application (discount applied but redemption not recorded), reduces invocation overhead, and the agent rarely needs to do these steps independently. Case for four tools: each step has distinct failure modes (coupon expired vs. discount calculation error vs. cart service down vs. database write failure), each failure warrants a different response, and separating them lets the agent observe and adapt. The answer depends on failure recovery needs: if partial application is dangerous, one atomic tool; if granular error handling matters, split them."},{id:"gr-2",difficulty:"intermediate",question:`An agent toolset has a "get_full_user_context" tool that fetches a user's profile, their recent orders, their open support tickets, and their subscription status — all in one call. What are the operational tradeoffs of this design versus four separate tools?`,hint:"Consider performance, failure handling, and what the agent actually needs in different workflow scenarios.",solution:"Coarse design advantages: one round-trip, simpler agent orchestration, consistent data snapshot across all four sources. Coarse design disadvantages: if the agent only needs the subscription status, it still pays for everything. If orders fetch fails, the entire call fails even if profile and subscription are fine. The agent cannot retry individual failures. Fine-grained design advantages: fetch only what is needed, recover from partial failures independently, cache each result separately. Disadvantage: more round-trips, risk of data inconsistency across calls made at different times. The right design often ends up as a middle ground: one tool per logical entity (user_profile, order_history, etc.)."},{id:"gr-3",difficulty:"advanced",question:"How does the intended autonomy level of the agent affect decisions about tool granularity? Should a high-autonomy agent (one that runs unsupervised for long periods) have coarser or finer tools than a low-autonomy agent (one that confirms each step with a human)?",hint:"Think about how each agent handles failure and what information it needs to adapt without human guidance.",solution:"High-autonomy agents generally need finer-grained tools, counterintuitively. Because they cannot ask a human when something goes wrong, they need maximum visibility into what happened at each step and maximum flexibility to choose a recovery strategy. Coarse tools fail opaquely, which is tolerable when a human can investigate — but catastrophic when the agent must self-recover. Low-autonomy agents, by contrast, can handle coarser tools more safely: when a tool fails, the agent can surface the ambiguity to the human for guidance. The human provides the recovery judgment the coarse tool cannot."}]})]})}const P=Object.freeze(Object.defineProperty({__proto__:null,default:g},Symbol.toStringTag,{value:"Module"}));function m(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("h2",{children:"Choosing the Right Tool"}),e.jsx("p",{children:"An agent rarely has just one tool. In most real systems, it has access to a set of tools — sometimes a large one — and must decide at each step which tool, if any, is the right one to invoke. Tool selection is one of the most frequent reasoning tasks an agent performs, and one of the most consequential. Choosing poorly wastes computation, corrupts state, or misses the actual need entirely."}),e.jsx(t,{title:"Tool Selection as Reasoning",number:"Concept 2.10",children:"Choosing the right tool is not a lookup operation — it is a reasoning problem. The agent must interpret the current goal, understand what each candidate tool does, assess whether the current state satisfies each tool's preconditions, and evaluate the risks of invocation versus inaction. This is a multi-dimensional judgment that benefits from the same careful reasoning the agent applies to any other decision."}),e.jsx("h3",{children:"The Tool Selection Decision Surface"}),e.jsx("p",{children:"When an agent considers which tool to use, it should be reasoning along at least these dimensions:"}),e.jsxs("ul",{children:[e.jsxs("li",{children:[e.jsx("strong",{children:"Relevance:"}),' Does this tool address the actual need, or just something adjacent to it? Overfitting to a tool that is "close enough" is a common failure mode.']}),e.jsxs("li",{children:[e.jsx("strong",{children:"Preconditions:"})," Are the conditions for this tool's correct operation currently satisfied? Invoking a tool whose preconditions are not met often produces misleading results or silent failures."]}),e.jsxs("li",{children:[e.jsx("strong",{children:"Risk:"})," How reversible is this tool's action? Does the current level of certainty justify taking an action of this consequence?"]}),e.jsxs("li",{children:[e.jsx("strong",{children:"Alternatives:"})," Is there a different tool that accomplishes the goal with lower risk, fewer assumptions, or a more appropriate scope?"]})]}),e.jsx(o,{title:"When in Doubt, Do Less",number:"Principle 2.8",children:'When an agent is uncertain which tool is correct, the right default is to do less — to gather more information before committing to an action, or to surface the ambiguity rather than guess. An agent that invokes the wrong tool "just to see what happens" risks real-world side effects that cannot be easily undone. Uncertainty about which tool to use is almost always a signal to pause and reason more carefully.'}),e.jsx("h3",{children:"Avoiding Tool Overreach"}),e.jsx("p",{children:'Tool overreach occurs when an agent uses a more powerful tool than the situation requires. An agent that has access to a "delete all records matching criteria" tool should not use it when a "delete this specific record by ID" tool is available and sufficient. More power means more potential for accidental harm.'}),e.jsx("p",{children:"The principle of least privilege applies to tool selection: use the tool with the narrowest scope that accomplishes the goal. This limits the blast radius of errors, makes behavior easier to audit, and produces workflows that are easier to reason about after the fact."}),e.jsx(a,{title:"The Closest Tool Is Not Always the Right Tool",type:"tip",children:"Agents often select tools based on surface similarity — the tool's name sounds related to the task, so they try it. This is a brittle selection strategy. A better approach is to reason from the outcome first: what state needs to exist after this step? Then find the tool whose postconditions describe that state most precisely. Working backward from the desired outcome produces more accurate tool selection than pattern-matching on names."}),e.jsx(i,{title:"Choosing the Right Tool",exercises:[{id:"crt-1",difficulty:"beginner",question:'An agent needs to find all customers who placed orders last month. It has access to: "search_customers" (searches by name or email), "get_customer_by_id" (retrieves a single record), and "query_orders_by_date_range" (returns order records with customer IDs for a given time period). Which tool should it use first, and why?',hint:"Think about what information the agent currently has and what each tool actually retrieves.",solution:'"query_orders_by_date_range" is the right first tool. The agent does not know the names or IDs of customers who ordered last month — it only knows the time period. This tool retrieves order records (which include customer IDs) for that period. Then, if needed, the agent can use those IDs with "get_customer_by_id". Using "search_customers" first would require knowing customer identifiers the agent does not yet have.'},{id:"crt-2",difficulty:"intermediate",question:'An agent is 80% confident it knows which record to delete, but not 100% certain. It has both a "delete_record_by_id" tool and a "get_record_by_id" tool. What should it do, and why does the level of certainty matter for tool selection?',hint:"Consider the reversibility of each tool and what an error means in each case.",solution:'The agent should use "get_record_by_id" first to confirm the record matches expectations before deleting. An 80% confidence level is insufficient for an irreversible action. If deletion is wrong, the data is gone. By retrieving first, the agent spends one extra step to raise its confidence near 100% before committing to the destructive action. The level of certainty required before taking an action should be proportional to the reversibility of that action.'},{id:"crt-3",difficulty:"advanced",question:"Describe a scenario where an agent has two tools that could both technically accomplish a goal, but choosing the wrong one leads to a subtle long-term problem rather than an immediate error. What principle should guide the choice?",hint:"Think about side effects, state accumulation, and downstream assumptions.",solution:'Example: an agent can update a record by using either "update_full_record" (replaces all fields) or "patch_record_field" (updates one field). Both can set the same target field to the desired value. But "update_full_record" silently overwrites every other field with whatever the agent currently has in context — which may be stale. Over time, concurrent updates cause data loss. The subtlety is that no individual call fails; the error accumulates. The guiding principle: prefer the narrowest-scope tool that achieves the goal. "patch_record_field" is correct here because it does exactly and only what is needed, without implicit side effects on unrelated state.'}]})]})}const D=Object.freeze(Object.defineProperty({__proto__:null,default:m},Symbol.toStringTag,{value:"Module"}));function y(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("h2",{children:"Sequential Tool Composition"}),e.jsx("p",{children:"Most agent tasks cannot be accomplished with a single tool call. They require a sequence of steps: gather information, process it, act on the result, verify the outcome. Sequential composition is the pattern of chaining tool invocations one after another, where each step's output informs the next step's input. It is the fundamental building block of agent workflows."}),e.jsx(t,{title:"Sequential Composition",number:"Concept 2.11",children:"Sequential composition is the arrangement of tool calls into an ordered sequence where the agent completes one invocation, observes the result, updates its internal state, and then decides what to invoke next. Unlike a fixed pipeline, sequential composition is agent-directed: the agent chooses each next step based on what it has learned so far. This adaptive sequencing is what distinguishes an intelligent agent from a rigid script."}),e.jsx("h3",{children:"The Observe-Decide Loop"}),e.jsx("p",{children:"At the heart of sequential composition is a loop: the agent observes the result of one tool call, reasons about what it means, and decides whether to continue, branch, retry, or stop. This loop is the mechanism by which agents adapt to reality. Each tool call is not just a computation — it is a query to the world that updates the agent's beliefs and informs its next decision."}),e.jsx("p",{children:"The quality of sequential composition depends on how well the agent uses each observation. An agent that ignores partial results, fails to propagate important context across steps, or does not adjust its plan when tool outputs are unexpected is not truly composing sequentially — it is just executing a fixed script with extra steps."}),e.jsx(s,{title:"The Detective's Investigation",children:"A detective does not arrive at a crime scene with a fixed list of people to arrest. They gather evidence, form a hypothesis, gather more evidence that confirms or challenges that hypothesis, revise, and eventually reach a conclusion. Each clue gathered changes what they look for next. Sequential composition works the same way: the agent forms a goal, gathers the first piece of relevant information, and lets what it learns shape every subsequent step. The investigation adapts to reality."}),e.jsx(o,{title:"Each Step Should Justify the Next",number:"Principle 2.9",children:"In a well-composed sequence, every tool invocation either directly accomplishes part of the goal or provides information necessary to plan the next step. If an agent is invoking a tool and cannot clearly articulate how the result will inform or advance the task, that invocation is likely unnecessary. Purposeless tool calls waste capacity and introduce noise into the agent's reasoning context."}),e.jsx("h3",{children:"Managing State Across Steps"}),e.jsx("p",{children:"Sequential composition requires the agent to carry state across steps. Information retrieved in step one must be available in step three. Errors encountered in step two must influence whether step three runs at all. This state management is often where sequential composition breaks down: earlier context is forgotten, error signals are not propagated, or the agent loses track of what it was originally trying to do."}),e.jsx("p",{children:"Effective sequential composition requires explicit attention to what information is load-bearing across steps — what the agent absolutely must not lose between invocations. Design workflows so that critical identifiers, permissions, and observations are surfaced at each step rather than assumed to be retained."}),e.jsx(i,{title:"Sequential Composition",exercises:[{id:"sq-1",difficulty:"beginner",question:'An agent must accomplish this goal: "Find the most recent support ticket for customer ID 4821, and update its priority to high." Describe the sequence of tool calls needed and what information must be carried from step to step.',hint:"What does the agent need to know before it can call the update tool?",solution:'Step 1: call "get_support_tickets_by_customer(customer_id=4821, sort=recent)" to find all tickets. Step 2: examine the results to identify the most recent ticket ID — this is the critical piece of state to carry forward. Step 3: call "update_ticket_priority(ticket_id=<result from step 2>, priority=high)". The ticket ID is the load-bearing state that bridges the two steps. Without explicitly tracking it, step 3 cannot proceed correctly.'},{id:"sq-2",difficulty:"intermediate",question:"An agent is in the middle of a five-step workflow. Step 3 returns an unexpected but valid result: the record the agent was looking for does not exist. How should a well-designed sequential composition handle this, versus how a poorly designed one would?",hint:'Think about what "observe and adapt" means in practice when reality does not match expectations.',solution:'Well-designed: the agent treats the "not found" as a signal, not an error. It pauses to assess: Was the ID correct? Should it search by other criteria? Should it create the record? It updates its plan based on what it learned and branches to the appropriate next action. Poorly designed: the agent either stops with an error, or worse, continues as if the record exists — passing a null or placeholder into step 4, which corrupts the rest of the workflow. The key difference is whether the agent treats each result as informative and plan-shaping, or as something to silently handle and continue past.'},{id:"sq-3",difficulty:"advanced",question:"How does context window limitation affect sequential composition, and what design strategies can mitigate this problem for long agent workflows?",hint:"Consider what happens to earlier tool results as the workflow grows longer.",solution:`As a sequential workflow grows longer, earlier tool results are pushed further back in the agent's context and may become truncated or effectively invisible to the agent's reasoning. The agent may "forget" critical state from early steps. Mitigation strategies include: (1) Summarization — after each step, distilling results into a compact working memory that captures only the load-bearing information. (2) Anchoring — periodically restating the original goal and key accumulated facts. (3) Workflow structuring — breaking long workflows into bounded sub-goals, each with their own compact context. (4) Explicit handoff artifacts — having the agent write key state to an external scratchpad tool that can be re-read as needed, rather than relying on context alone.`}]})]})}const O=Object.freeze(Object.defineProperty({__proto__:null,default:y},Symbol.toStringTag,{value:"Module"}));function w(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("h2",{children:"Parallel Tool Composition"}),e.jsx("p",{children:"Not every tool invocation depends on the result of the previous one. When multiple tool calls are independent of each other — when they need no information from one another and do not conflict in their effects — they can be executed in parallel. Parallel composition is a powerful pattern for reducing the latency and turn-count of agent workflows. Used correctly, it makes agents dramatically more efficient. Used incorrectly, it produces race conditions, conflicting writes, and failures that are difficult to reproduce."}),e.jsx(t,{title:"Parallel Composition",number:"Concept 2.12",children:"Parallel composition is the simultaneous invocation of two or more tools whose execution does not depend on each other's results and whose effects do not conflict. It is appropriate when the tools are reading independent data sources, performing independent computations, or acting on disjoint parts of the world. It is dangerous when the tools share state, when one tool's output is the other's input, or when their combined effects could be inconsistent."}),e.jsx("h3",{children:"When Parallelism Is Safe"}),e.jsx("p",{children:"The key question before running tools in parallel is: are these invocations truly independent? Independence has two components:"}),e.jsxs("ul",{children:[e.jsxs("li",{children:[e.jsx("strong",{children:"Data independence:"})," Neither tool needs to read the output of the other to function correctly. If tool A's result must feed into tool B, they are not independent — they must be sequential."]}),e.jsxs("li",{children:[e.jsx("strong",{children:"Effect independence:"})," The tools do not write to the same location, the same record, or the same external state. Two tools that both update the same field in a database are not independent — their parallel execution risks a write conflict or a lost update."]})]}),e.jsx("p",{children:"Read-only tools are almost always safe to parallelize. Two information retrieval calls that fetch data from different sources have no interaction surface and no conflict risk. Gathering data in parallel is one of the most reliable uses of this pattern."}),e.jsx(o,{title:"Parallelize Reads, Serialize Writes",number:"Principle 2.10",children:"A practical default for parallel composition: read operations can almost always be parallelized safely. Write operations — anything that modifies external state — should be carefully evaluated for effect independence before being parallelized. When in doubt about two write operations, serialize them. The latency cost of sequential execution is almost always smaller than the debugging cost of a parallelism-induced data corruption."}),e.jsx("h3",{children:"Handling Partial Failures in Parallel Execution"}),e.jsx("p",{children:"When multiple tools run in parallel and one of them fails, the agent faces a complex recovery problem. The other tools may have already succeeded and taken irreversible actions. The agent must decide: should the overall task abort? Should it proceed with the successful results and ignore the failed one? Should it retry only the failed tool?"}),e.jsx("p",{children:"This complexity is not a reason to avoid parallelism, but it is a reason to plan for it explicitly. The agent's design should specify, for each parallel composition, how partial failures are handled — before the failure occurs, not in the moment."}),e.jsx(n,{title:"Parallelism Amplifies Race Conditions",children:"Any shared state between parallel tools is a potential race condition. Two tools that each check a balance, determine it is sufficient, and then both attempt to deduct from it may both succeed even if only one should have. Race conditions in agent workflows are especially difficult to detect because they are timing-dependent and may only manifest under specific load conditions. If shared mutable state is involved, serialize."}),e.jsx(i,{title:"Parallel Composition",exercises:[{id:"par-1",difficulty:"beginner",question:"An agent must: (a) fetch the user's profile, (b) fetch the user's recent orders, (c) update the user's last-login timestamp, and (d) send a welcome-back email. Which of these can be parallelized, and which must be sequential or serialized?",hint:"Check each pair for data dependence and effect independence.",solution:"(a) and (b) can be parallelized — both are reads from independent data sources. (c) and (d) depend on context: (c) is a write operation that can run concurrently with reads (a) and (b) since it writes to a different field. (d) should run after the profile is fetched, since the email may need to include personalized content from the profile. So: parallelize (a), (b), and (c) together; run (d) after (a) completes with the profile data."},{id:"par-2",difficulty:"intermediate",question:"An agent is orchestrating three independent API calls in parallel. One of them fails with a network timeout. Describe the different recovery strategies the agent might take and when each is appropriate.",hint:"Consider whether the failed call's result is essential or optional to the overall task.",solution:"Strategy 1 — Abort all: appropriate when the failed call's result is essential and the other calls' results are meaningless without it. Strategy 2 — Proceed with partial results: appropriate when the failed call is optional and the successful results are independently useful. Strategy 3 — Retry the failed call only: appropriate when the tool is idempotent and the failure was transient (network timeout). Strategy 4 — Surface the gap to the user: appropriate when the agent cannot safely determine which strategy is correct without human judgment. The right choice depends on whether the failed result is load-bearing for the task goal."},{id:"par-3",difficulty:"advanced",question:"Two agent tasks run in parallel: Task A reads the account balance and, based on it, triggers a refund. Task B reads the same account balance and, based on it, triggers a charge. Describe the race condition that can occur and a design-level solution to prevent it.",hint:"Think about the time between reading the balance and acting on it.",solution:"Both tasks read the balance at approximately the same time. Both see a sufficient balance. Task A triggers a refund (increasing the balance). Task B triggers a charge (decreasing the balance). But the charge may have been decided based on a balance that the refund has now inflated — the two operations are not operating on a consistent view of state. This is a classic check-then-act race condition. Design solutions: (1) Use optimistic locking — each operation includes the balance value it read; the write is rejected if the balance has changed since the read. (2) Serialize all balance-modifying operations through a queue or lock. (3) Use atomic compare-and-swap operations at the storage level. Parallelism and shared mutable state require explicit concurrency control."}]})]})}const E=Object.freeze(Object.defineProperty({__proto__:null,default:w},Symbol.toStringTag,{value:"Module"}));function b(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("h2",{children:"Tool Chaining"}),e.jsx("p",{children:"Tool chaining is the practice of feeding the output of one tool directly as the input to the next. It is sequential composition made explicit: the tools are deliberately designed to connect, with each one's outputs shaped to satisfy the next one's input requirements. When done well, chaining creates workflows that are powerful, composable, and easy to reason about. When done poorly, it creates brittle pipelines where a single unexpected output breaks everything downstream."}),e.jsx(t,{title:"The Chain as a Data Flow",number:"Concept 2.13",children:"A tool chain can be understood as a data flow: information enters at the first tool, is transformed by each successive tool, and exits as a result at the end. At each connection between tools, there is an implicit contract: the upstream tool's output format must match the downstream tool's input format. Chains break when these formats diverge — either because the upstream tool changed, because the agent misread the output, or because an error case was not anticipated in the chain's design."}),e.jsx("h3",{children:"Designing for Chainability"}),e.jsx("p",{children:"Tools that chain well share specific properties. Their outputs are structured and predictable — not free-form text that the next tool must parse, but well-typed values that the next tool can consume directly. Their error cases are distinct from their success cases so the agent can decide whether to continue the chain or abort. And their outputs contain the identifiers and references needed to construct the next call, without requiring the agent to do complex transformation."}),e.jsx("p",{children:"A tool that returns a flat string where the next tool expects a structured record is not chainable — not cleanly. The agent must act as a translator between them, interpreting free text and constructing the required structure. This interpretation step is a fragility point: it depends on the agent parsing accurately, which is not guaranteed."}),e.jsx(o,{title:"Design Outputs with Downstream Consumers in Mind",number:"Principle 2.11",children:"A tool's output format should be designed with the most common downstream use cases in mind. If a tool's result is almost always fed into another specific tool, the output should be structured to make that next invocation trivial. Tool designers who think only about the happy-path return value, and not about how that value will be used by the next step, produce tools that are chainable in theory but brittle in practice."}),e.jsx("h3",{children:"Chain Length and Fragility"}),e.jsx("p",{children:"Long chains are fragile chains. Every link adds a potential failure point. Every translation between tools adds a potential misinterpretation. A chain of ten tools where each has a 95% success rate has only a 60% chance of end-to-end success. This is not a reason to avoid chaining, but it is a reason to minimize unnecessary links and to ensure each link in the chain is as reliable as possible."}),e.jsx("p",{children:"When designing a chain, ask at each link: is this tool the right scope for what needs to happen here? Could two tools be merged into one without sacrificing important visibility? Could one tool be eliminated by reshaping the upstream tool's output? Shorter chains that do the same work are almost always better."}),e.jsx(a,{title:"The Translation Tax",type:"intuition",children:"Every time an agent must interpret or transform a tool's output before passing it to the next tool, it pays a translation tax: context is consumed, interpretation can fail, and the agent's reasoning is one step further from the original goal. Well-designed tool chains minimize this tax by producing outputs that the next tool can consume directly, without the agent needing to act as an adapter."}),e.jsx(i,{title:"Tool Chaining",exercises:[{id:"ch-1",difficulty:"beginner",question:'Tool A returns a user object with an "account_id" field. Tool B requires an "accountId" parameter. The agent must connect these. What design problem exists here, and what is the ideal solution?',hint:"Think about whether the agent should be responsible for this transformation.",solution:'The naming inconsistency (snake_case vs camelCase) forces the agent to recognize that "account_id" and "accountId" are the same thing and perform an explicit mapping. This is a minor translation tax — the agent can handle it, but only if it reasons correctly about the equivalence. The ideal solution is to standardize naming conventions across all tools in a toolset so no such mapping is required. The second-best solution is to document the connection explicitly in tool descriptions so the agent knows these map to each other.'},{id:"ch-2",difficulty:"intermediate",question:`An agent has a three-tool chain: (1) search for products, (2) check inventory for each result, (3) add the available products to a quote. Step 2 must be called once per product from step 1. How does this "fan-out" pattern affect the chain's complexity and reliability?`,hint:"Think about what happens when there are 20 results from step 1, and what happens if step 2 fails for some of them.",solution:'Fan-out dramatically increases invocation count and introduces partial-failure complexity. With 20 products, step 2 runs 20 times. If 3 of those calls fail (network errors, timeouts), the agent must decide: proceed with the 17 that succeeded, retry the 3, or abort the entire chain. Each partial failure requires a recovery decision. The chain is now substantially more complex than a linear three-step sequence. Design mitigations include: batching (a single "check_inventory_batch" call that accepts multiple IDs), retry logic with idempotency guarantees, and explicit partial-success handling in the chain design.'},{id:"ch-3",difficulty:"advanced",question:"Explain the difference between a brittle chain (one that breaks when any tool produces an unexpected output) and a resilient chain (one that handles unexpected outputs gracefully). What structural properties distinguish them?",hint:"Think about error path design, validation at each step, and how the agent responds to values outside the expected range.",solution:"A brittle chain assumes every tool returns the expected happy-path output and passes it directly to the next tool. When any tool returns an unexpected value (empty result, partial data, error code embedded in a success response), the next tool receives invalid input and fails in ways that may be hard to trace. A resilient chain validates each tool's output before passing it forward: it checks for expected fields, handles empty and error cases explicitly, and has predefined recovery paths for each failure mode. Structural properties of resilient chains: (1) each tool's output is validated before the next call; (2) error cases have explicit routing (retry, abort, branch, escalate); (3) the chain can report which step failed and what it received; (4) partial results are explicitly flagged as partial, not silently treated as complete."}]})]})}const M=Object.freeze(Object.defineProperty({__proto__:null,default:b},Symbol.toStringTag,{value:"Module"}));function v(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("h2",{children:"Graceful Failure in Tool Composition"}),e.jsx("p",{children:"Tools fail. Networks drop. Services go down. Inputs arrive that the tool never anticipated. In any real agent deployment, tool failures are not the exception — they are a routine part of operation. The question is not whether failures will occur, but whether the agent is designed to handle them gracefully: to detect them accurately, respond proportionally, and recover without causing further harm."}),e.jsx(t,{title:"Graceful Failure",number:"Concept 2.14",children:"Graceful failure is the property of a system that encounters errors without catastrophic consequence. An agent that fails gracefully detects tool errors accurately, responds with an appropriate recovery action (retry, alternative tool, escalation, or abort), and never allows a failed tool call to silently corrupt the rest of its workflow. Graceful failure is not about eliminating errors — it is about ensuring that errors are visible, bounded, and recoverable."}),e.jsx("h3",{children:"The Four Responses to Tool Failure"}),e.jsx("p",{children:"When a tool call fails, an agent has four basic responses available. The right choice depends on the nature of the failure and the reversibility of what has already been done:"}),e.jsxs("ul",{children:[e.jsxs("li",{children:[e.jsx("strong",{children:"Retry:"})," Appropriate for transient failures (network errors, temporary service unavailability) when the tool is idempotent. Retry with a delay and a limit — infinite retries cause infinite hangs."]}),e.jsxs("li",{children:[e.jsx("strong",{children:"Alternative tool:"})," When a tool is unavailable but another tool can achieve a similar result, the agent pivots. This requires knowing, in advance, which tools can substitute for which."]}),e.jsxs("li",{children:[e.jsx("strong",{children:"Partial completion:"})," When part of the workflow succeeded before the failure, the agent may be able to report what it accomplished and flag what remains incomplete, rather than discarding the entire effort."]}),e.jsxs("li",{children:[e.jsx("strong",{children:"Escalation:"})," When the agent cannot safely determine the right recovery path, it surfaces the failure to a human or a supervisory system. This is always the right choice when uncertainty is high and stakes are significant."]})]}),e.jsx(o,{title:"Never Swallow Failures Silently",number:"Principle 2.12",children:"The most dangerous response to a tool failure is to treat it as a success and continue. Once a failure is silently absorbed into the workflow, all subsequent reasoning builds on a false foundation. The agent may take further consequential actions based on a state that does not actually exist. Loud, explicit failure handling is always safer than silent continuation, even when it means stopping short of the goal."}),e.jsx("h3",{children:"Designing Workflows for Failure Tolerance"}),e.jsx("p",{children:'Failure tolerance is not something you add to a workflow after the fact. It must be designed in from the beginning. At every step in a tool composition, the designer should ask: "What happens here if the tool returns an error? What if it times out? What if it returns a result that is technically valid but semantically wrong for this context?"'}),e.jsx("p",{children:"Workflows with explicit failure paths at each step are longer to design but far shorter to debug. Every anticipated failure case that has a defined response is one less failure mode that can propagate silently through the rest of the workflow."}),e.jsx(n,{title:"Retry Loops Without Limits Are Denial-of-Service",children:"An agent that retries a failing tool without a maximum retry count or backoff delay can loop indefinitely, consuming resources and blocking other work. Always bound retries: a maximum count, an increasing delay between attempts, and a defined fallback when the limit is reached. Unbounded retry loops are one of the most common pathological failure modes in production agent deployments."}),e.jsx(i,{title:"Graceful Failure Patterns",exercises:[{id:"gf-1",difficulty:"beginner",question:'An agent calls a "get_weather" tool and receives a "service unavailable" error. It calls a "send_daily_briefing" tool next anyway, constructing a briefing without weather data. What has gone wrong, and what should the agent have done?',hint:"Consider whether the failure was detected, and whether the downstream action was appropriate given that detection.",solution:'The agent detected the failure (it received a "service unavailable" error) but did not respond to it — it continued as if weather data were available. The briefing now omits weather or contains stale data without flagging this to the user. The correct behavior: after receiving the error, the agent should either (1) retry the weather tool if it was a transient failure, (2) note in the briefing that weather data was unavailable today, or (3) delay sending until weather data is available. Silently proceeding is the worst option.'},{id:"gf-2",difficulty:"intermediate",question:"Design the failure handling for a three-step workflow: (1) reserve inventory, (2) process payment, (3) confirm order. Step 2 fails after step 1 has succeeded. What should the agent do, and why is this harder than a failure at step 1?",hint:"Think about what state now exists in the world that did not before, and whether it is safe to leave it.",solution:"Step 1 has already reserved inventory — real state exists that must be addressed. If the agent simply aborts, the reservation persists indefinitely, blocking that inventory from other customers. The correct response: trigger a compensating action (release the reservation) before reporting the failure. This is harder than a step 1 failure because the agent must actively undo completed work, not just stop. The principle here is that failure handling in multi-step workflows must account for already-committed side effects and provide compensating actions for each one."},{id:"gf-3",difficulty:"advanced",question:'What is the difference between a "retry-safe" failure and a "retry-dangerous" failure? Give an example of each, and describe how an agent should distinguish between them before deciding to retry.',hint:"Think about what property of the tool and the failure type determines whether retrying makes things better or worse.",solution:'A retry-safe failure is one where retrying cannot make the situation worse: the tool is idempotent (so a duplicate call has no additional effect) and the failure was transient (the underlying problem is likely resolved by the time of the retry). Example: a "get_user_profile" call that times out — retrying fetches the same profile with no side effects. A retry-dangerous failure is one where retrying can cause harm: the tool is non-idempotent or the failure was due to invalid input, not a transient condition. Example: a "send_payment" call that failed with "insufficient funds" — retrying does not fix the root cause and may trigger additional failed-payment fees. An agent should check: (1) Is the tool idempotent? (2) Is the error code indicating a transient condition (timeout, service unavailable) or a permanent one (invalid input, permission denied, insufficient funds)? Only retry for transient failures on idempotent tools.'}]})]})}const z=Object.freeze(Object.defineProperty({__proto__:null,default:v},Symbol.toStringTag,{value:"Module"}));export{j as a,q as b,A as c,_ as d,I as e,C as f,S as g,W as h,P as i,D as j,O as k,E as l,M as m,z as n,k as s};
